std::wstring PluginDirectory()
{
    wchar_t modulePath[MAX_PATH] = {};
    const DWORD length = GetModuleFileNameW(reinterpret_cast<HMODULE>(&__ImageBase), modulePath, MAX_PATH);
    if (length == 0 || length == MAX_PATH)
    {
        return L".";
    }

    std::wstring path(modulePath, length);
    const std::wstring::size_type slash = path.find_last_of(L"\\/");
    if (slash == std::wstring::npos)
    {
        return L".";
    }
    return path.substr(0, slash);
}

std::wstring BodyNoteConfigFilePath()
{
    return PluginDirectory() + L"\\ZiDonCuTu_note_format.ini";
}

void EnsureDefaultBodyNoteConfigFile(const std::wstring& path)
{
    const DWORD attributes = GetFileAttributesW(path.c_str());
    if (attributes != INVALID_FILE_ATTRIBUTES && (attributes & FILE_ATTRIBUTE_DIRECTORY) == 0)
    {
        return;
    }

    std::ofstream file(path, std::ios::binary);
    if (!file)
    {
        return;
    }

    const unsigned char bom[] = { 0xEF, 0xBB, 0xBF };
    file.write(reinterpret_cast<const char*>(bom), sizeof(bom));
    file
        << "# Placeholders: {number}, {number=}, {material}, {thickness}, {quantity}, {mirror}\r\n"
        << "# Use Chinese placeholders: {\xE7\xBC\x96\xE5\x8F\xB7}, {\xE7\xBC\x96\xE5\x8F\xB7=}, {\xE6\x9D\x90\xE6\x96\x99}, {\xE5\x8E\x9A\xE5\xBA\xA6}, {\xE6\x95\xB0\xE9\x87\x8F}, {\xE9\x95\x9C\xE5\x83\x8F}\r\n"
        << "# Use \\n for multiple lines.\r\n\r\n"
        << "[\xE6\xA0\x87\xE6\xB3\xA8\xE6\xB3\xA8\xE9\x87\x8A]\r\n"
        << kDefaultBodyNoteFormat << "\r\n";
}

