bool IsEmptyText(const NXOpen::NXString& value)
{
    const char* text = value.GetLocaleText();
    return text == NULL || strlen(text) == 0;
}

std::string TrimText(std::string value)
{
    value.erase(value.begin(), std::find_if(value.begin(), value.end(), [](unsigned char ch) {
        return !std::isspace(ch);
        }));
    value.erase(std::find_if(value.rbegin(), value.rend(), [](unsigned char ch) {
        return !std::isspace(ch);
        }).base(), value.end());
    return value;
}

std::string RemoveUtf8Bom(const std::string& value)
{
    if (value.size() >= 3 &&
        static_cast<unsigned char>(value[0]) == 0xEF &&
        static_cast<unsigned char>(value[1]) == 0xBB &&
        static_cast<unsigned char>(value[2]) == 0xBF)
    {
        return value.substr(3);
    }
    return value;
}

void ReplaceAllText(std::string& text, const std::string& from, const std::string& to)
{
    if (from.empty())
    {
        return;
    }

    size_t pos = 0;
    while ((pos = text.find(from, pos)) != std::string::npos)
    {
        text.replace(pos, from.length(), to);
        pos += to.length();
    }
}

std::string DecodeConfigEscapes(const std::string& value)
{
    std::string result;
    bool escape = false;
    for (size_t i = 0; i < value.size(); ++i)
    {
        const char ch = value[i];
        if (escape)
        {
            if (ch == 'n')
            {
                result += '\n';
            }
            else if (ch == 'r')
            {
                result += '\r';
            }
            else if (ch == 't')
            {
                result += '\t';
            }
            else
            {
                result += ch;
            }
            escape = false;
            continue;
        }

        if (ch == '\\')
        {
            escape = true;
            continue;
        }
        result += ch;
    }

    if (escape)
    {
        result += '\\';
    }
    return result;
}

bool TryReadBodyNoteFormatLine(const std::string& rawLine, std::string& formatText)
{
    std::string line = TrimText(RemoveUtf8Bom(rawLine));
    if (line.empty() || line[0] == '#' || line[0] == ';')
    {
        return false;
    }
    if (line.front() == '[' && line.back() == ']')
    {
        return false;
    }

    const std::string key = "body_note_format";
    if (line.compare(0, key.size(), key) == 0)
    {
        const size_t equalPos = line.find('=');
        if (equalPos != std::string::npos)
        {
            line = TrimText(line.substr(equalPos + 1));
        }
    }

    if (line.empty())
    {
        return false;
    }

    formatText = DecodeConfigEscapes(line);
    return !formatText.empty();
}
