std::string BuildBodyNoteText(NXOpen::Part* part, NXOpen::Body* body, bool includeNumber)
{
    const std::string material = ReadMaterialReferenceText(part, body);
    std::string thickness = ObjectAttributeReferenceText(body, "Z");
    if (thickness.empty())
    {
        thickness = ReadAttributeText(body, "Z");
    }
    const std::string quantity = ReadBodyTotalQuantityReferenceText(part, body);
    std::string mirror = ObjectAttributeReferenceText(body, "MIRR");
    if (mirror.empty())
    {
        mirror = ReadAttributeText(body, "MIRR");
    }
    std::string number = includeNumber ? ObjectAttributeReferenceText(body, "bianhao") : "";
    if (includeNumber && number.empty())
    {
        number = ReadAttributeText(body, "bianhao");
    }

    std::string line = LoadBodyNoteFormat();
    ReplaceAllText(line, "{\xE7\xBC\x96\xE5\x8F\xB7=}", number.empty() ? "" : number + "=");
    ReplaceAllText(line, "{\xE7\xBC\x96\xE5\x8F\xB7}", number);
    ReplaceAllText(line, "{\xE6\x9D\x90\xE6\x96\x99}", material);
    ReplaceAllText(line, "{\xE5\x8E\x9A\xE5\xBA\xA6}", thickness);
    ReplaceAllText(line, "{\xE6\x95\xB0\xE9\x87\x8F}", quantity.empty() ? "1" : quantity);
    ReplaceAllText(line, "{\xE9\x95\x9C\xE5\x83\x8F}", mirror);
    return line;
}

std::vector<NXOpen::NXString> BuildBodyNoteLines(NXOpen::Part* part, NXOpen::Body* body, bool includeNumber)
{
    const std::string noteText = BuildBodyNoteText(part, body, includeNumber);
    std::vector<NXOpen::NXString> lines;
    std::string current;
    for (size_t i = 0; i < noteText.size(); ++i)
    {
        const char ch = noteText[i];
        if (ch == '\r')
        {
            continue;
        }
        if (ch == '\n')
        {
            lines.push_back(NXOpen::NXString(current.c_str(), NXOpen::NXString::UTF8));
            current.clear();
            continue;
        }
        current += ch;
    }
    lines.push_back(NXOpen::NXString(current.c_str(), NXOpen::NXString::UTF8));
    return lines;
}

