//------------------------------------------------------------------------------
//Callback Name: update_cb
//------------------------------------------------------------------------------
int BODYNOT::update_cb(NXOpen::BlockStyler::UIBlock* block)
{
    try
    {
        if(block == toggle0)
        {
        //---------Enter your code here-----------
        }
        else if(block == selection0)
        {
            UfSessionGuard ufSession;
            if (!ufSession.IsInitialized())
            {
                BODYNOT::theUI->NXMessageBox()->Show("Block Styler", NXOpen::NXMessageBox::DialogTypeError, "UFUN 初始化失败，无法继续创建实体标注。");
                return 0;
            }

            //获取选择对象TAG_T
            PropertyList* selection0Props = selection0->GetProperties();
            std::vector<NXOpen::TaggedObject*> notbody1 = selection0Props->GetTaggedObjectVector("SelectedObjects");
            delete selection0Props;
            selection0Props = NULL;

            if (notbody1.empty())
            {
                BODYNOT::theUI->NXMessageBox()->Show("Block Styler", NXOpen::NXMessageBox::DialogTypeError, "未选择对象，请先选择实体或工程图视图。");
                return 0;
            }

            PropertyList* toggle01Props = toggle01->GetProperties();
            bool Thetoggle01 = (toggle01Props->GetLogical("Value") != 0);
            delete toggle01Props;
            toggle01Props = NULL;

            NXOpen::Body* body1 = ResolveSelectedBody(notbody1[0]);
            if (body1 == NULL)
            {
                BODYNOT::theUI->NXMessageBox()->Show("Block Styler", NXOpen::NXMessageBox::DialogTypeError, "未能从所选对象取得实体。请选择实体，或选择包含模型曲线的工程图视图。");
                return 0;
            }

            DestroyDraftingNoteBuilder();
            NXOpen::Annotations::SimpleDraftingAid* nullNXOpen_Annotations_SimpleDraftingAid(NULL);
            draftingNoteBuilder1 = workPart->Annotations()->CreateDraftingNoteBuilder(nullNXOpen_Annotations_SimpleDraftingAid);
            draftingNoteBuilder1->Origin()->Plane()->SetPlaneMethod(NXOpen::Annotations::PlaneBuilder::PlaneMethodTypeXyPlane);
            draftingNoteBuilder1->Origin()->SetAnchor(NXOpen::Annotations::OriginBuilder::AlignmentPositionMidCenter);
            draftingNoteBuilder1->Origin()->SetInferRelativeToGeometry(false);
            draftingNoteBuilder1->Style()->LetteringStyle()->SetGeneralTextColor(workPart->Colors()->Find("Emerald"));

            double x = 0.0;
            double y = 0.0;
            bool foundFlatPattern = false;
            std::vector<Features::Feature*> Feature01 = workPart->Features()->GetFeatures();
            for (size_t i = 0; i < Feature01.size(); i++)
            {
                if (strcmp(Feature01[i]->FeatureType().GetLocaleText(), "FLAT_PATTERN") == 0)
                {
                    NXOpen::Features::FlatPattern* convertToSheetmetal1 = dynamic_cast<NXOpen::Features::FlatPattern*>(NXOpen::NXObjectManager::Get(Feature01[i]->Tag()));
                    if (convertToSheetmetal1 == NULL)
                        continue;

                    NXOpen::Features::SheetMetal::FlatPatternBuilder* flatPatternBuilder1 = workPart->Features()->SheetmetalManager()->CreateFlatPatternBuilder(convertToSheetmetal1);
                    NXOpen::Face* FACE1A = flatPatternBuilder1->UpwardFace()->Value();
                    if (FACE1A != NULL)
                    {
                        std::vector<NXOpen::Face*> bodyFaces = body1->GetFaces();
                        for (size_t C = 0; C < bodyFaces.size(); C++)
                        {
                            if (bodyFaces[C]->Tag() == FACE1A->Tag())
                            {
                                x = convertToSheetmetal1->GetRealAttribute("Minimum X");
                                y = convertToSheetmetal1->GetRealAttribute("Minimum Y");
                                foundFlatPattern = true;
                                break;
                            }
                        }
                    }
                    flatPatternBuilder1->Destroy();
                    break;
                }
            }
            int Body1ID = 0;
            Body1ID = body1->GetIntegerAttribute("BodyID");
            std::vector<NXOpen::NXString> Kong(1), text11;
            Kong[0] = "";

            if (Thetoggle01)
            {
                char ExName1YY[256];
                char ExName1XX[256];




                sprintf(ExName1YY, "YY_%d", Body1ID);
                sprintf(ExName1XX, "XX_%d", Body1ID);
                std::string textX = ReadExpressionIntegerText(workPart, ExName1XX);
                std::string textY = ReadExpressionIntegerText(workPart, ExName1YY);
                if (!textX.empty() && !textY.empty())
                {
                    text11.push_back((textX + "X" + textY + " ").c_str());
                }
                else
                {
                    if (foundFlatPattern)
                    {
                        char flatSizeText[128];
                        sprintf(flatSizeText, "%.2fX%.2f ", x, y);
                        text11.push_back(flatSizeText);
                    }
                }
            }

            draftingNoteBuilder1->Style()->LetteringStyle()->SetGeneralTextLineSpaceFactor(1.5);
            //获取编号开关值
            PropertyList* toggle0Props = toggle0->GetProperties();
            bool Thetoggle0 = (toggle0Props->GetLogical("Value") != 0);
            delete toggle0Props;
            toggle0Props = NULL;
            std::vector<NXOpen::NXString> finalText;
            for (size_t textIndex = 0; textIndex < text11.size(); ++textIndex)
            {
                if (!IsEmptyText(text11[textIndex]))
                {
                    finalText.push_back(text11[textIndex]);
                }
            }
            SetBodyDraftNoteTextFromConfig(draftingNoteBuilder1->Text()->TextBlock(), workPart, body1, Thetoggle0, finalText);
        }
        else if (block == toggle01)
        {

        }
        else if(block == point0)
        {
            UfSessionGuard ufSession;
            if (!ufSession.IsInitialized())
            {
                BODYNOT::theUI->NXMessageBox()->Show("Block Styler", NXOpen::NXMessageBox::DialogTypeError, "UFUN 初始化失败，无法提交实体标注。");
                return 0;
            }
            //Get the point
            PropertyList* pointPropertyList = point0->GetProperties();
            Point3d originPoint = pointPropertyList->GetPoint("Point");
            delete pointPropertyList;
            pointPropertyList = NULL;

            NXOpen::View* nullNXOpen_View(NULL);
            if (draftingNoteBuilder1 != NULL)
            {
                draftingNoteBuilder1->Origin()->Origin()->SetValue(NULL, nullNXOpen_View, originPoint);
                NXOpen::NXObject* nXObject1 = draftingNoteBuilder1->Commit();
                DestroyDraftingNoteBuilder();
            }


        }
    }
    catch(exception& ex)
    {
        //---- Enter your exception handling code here -----
        BODYNOT::theUI->NXMessageBox()->Show("Block Styler", NXOpen::NXMessageBox::DialogTypeError, ex.what());
    }
    return 0;
}

//------------------------------------------------------------------------------
//Callback Name: ok_cb
//------------------------------------------------------------------------------
int BODYNOT::ok_cb()
{
    int errorCode = 0;
    try
    {
        errorCode = apply_cb();
    }
    catch(exception& ex)
    {
        //---- Enter your exception handling code here -----
        errorCode = 1;
        BODYNOT::theUI->NXMessageBox()->Show("Block Styler", NXOpen::NXMessageBox::DialogTypeError, ex.what());
    }
    return errorCode;
}

